//   inputVec: 1 * tileOw
//   tmpVec: 1 * tileOw
//   scalarBuf: 1
// Total floats ~= (cout + 2) * tileOw + 1
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // per-core conservative
static constexpr uint32_t HARD_TILE_CAP = 2048;          // cap tile width to avoid long iters
static constexpr uint32_t ALIGN_ELEMS = 16;              // reasonable DMA alignment

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
