    const int32_t dilW    = attrs->GetAttrNum<int32_t>(5) ? *attrs->GetAttrPointer<int32_t>(5) : 3;
    const int32_t groups  = attrs->GetAttrNum<int32_t>(6) ? *attrs->GetAttrPointer<int32_t>(6) : 1;

    if (groups != 1) {
        return ge::GRAPH_FAILED; // only groups=1 supported
    }

    // Output dims
    const int64_t effKh = static_cast<int64_t>(Kh) + static_cast<int64_t>(Kh - 1) * (dilH - 1);
    const int64_t effKw = static_cast<int64_t>(Kw) + static_cast<int64_t>(Kw - 1) * (dilW - 1);

    const uint32_t Ho = static_cast<uint32_t>(
        (static_cast<int64_t>(H) + 2LL * padH - effKh) / strideH + 1LL);
    const uint32_t Wo = static_cast<uint32_t>(
