at::Tensor conv2d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    // Output tensor allocation inferred by NPU op
    // Use attributes fixed as per the PyTorch model:
    // stride=(1,1), padding=(2,4), dilation=(2,3), groups=1
    auto N = x.size(0);
    auto Cout = weight.size(0);
    auto H = x.size(2);
    auto W = x.size(3);
    auto Kh = weight.size(2);
    auto Kw = weight.size(3);
    // Compute output dims on host for allocation
    auto effKh = Kh + (Kh - 1) * (2 - 1);
    auto effKw = Kw + (Kw - 1) * (3 - 1);
    auto Ho = (H + 2 * 2 - effKh) / 1 + 1;
    auto Wo = (W + 2 * 4 - effKw) / 1 + 1;

    at::Tensor y = at::empty({N, Cout, Ho, Wo}, x.options().dtype(x.dtype()));

    EXEC_NPU_CMD(aclnnConvStandard2dSquareInputAsymmetricKernelDilatedPaddedCustom,
                 x, weight,
                 1, 1, // stride_h, stride_w
                 2, 4, // pad_h, pad_w
                 2, 3, // dilation_h, dilation_w
                 1,    // groups
                 y);
    return y;
